import { Anthropic } from '@anthropic-ai/sdk';
import { Vex } from 'vex-sdk';

const anthropic = new Anthropic({ apiKey: 'your-anthropic-key' });
const vex = new Vex({ apiKey: 'your-vex-key' });

type ToolUseResponse = any;

const response: ToolUseResponse = await anthropic.messages.create({
  model: 'claude-3-5-sonnet-20240620',
  max_tokens: 1024,
  tools: [{
    name: 'get_product_claims',
    description: 'Fetch verified claims',
    input_schema: { type: 'object', properties: { sku: { type: 'string' } } }
  }],
  messages: [{ role: 'user', content: 'Best features of product XYZ?' }]
});

const verification = await vex.verify({
  response,
  policy: 'ftc-product-claims',
  context: {
    sku: 'XYZ',
    allowedClaims: ['long battery', 'water resistant'],
    bannedPhrases: ['best ever', 'unbeatable']
  }
});

if (verification.passed) {
  console.log(response.content[0].text);
} else {
  throw new Error('FTC claim violation detected');
}
